    private string _phone = string.Empty;
    private string _address = string.Empty;
    private string _emailError = string.Empty;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<RefModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = string.Empty;

    // ── Mutable working models ──

    private record WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record RefModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }

    // ── Navigation ──

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _error = string.Empty;
            _currentStep = step;
        }
    }

    private void PrevStep()
    {
        _error = string.Empty;
        if (_currentStep > 1) _currentStep--;
    }

    private async Task NextStep()
    {
        _error = string.Empty;
        _emailError = string.Empty;

        if (!ValidateCurrentStep()) return;

        if (_currentStep == 1)
        {
            _loading = true;
            try
            {
                var valid = await ApplicationService.ValidateEmailAsync(_email);
                if (!valid)
                {
                    _emailError = "Please enter a valid email address.";
                    _loading = false;
                    return;
                }
            }
            finally { _loading = false; }
        }

        if (_currentStep < 5) _currentStep++;
    }

    // ── Validation ──

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
                    string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
                {
                    _error = "Please fill in all required fields.";
                    return false;
                }
                return true;

            case 2:
                foreach (var w in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(w.Company) || string.IsNullOrWhiteSpace(w.Title))
                    {
                        _error = "Each position must have a company name and job title.";
                        return false;
                    }
