                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" value="@r.Phone"
                                           @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                        </div>
                    </div>
                }
