@page "/apply"
@rendermode InteractiveServer
@using sv_f91deabe9ca64082bfb87c6605085bf6.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative" aria-label="Application steps">
        @for (int i = 0; i < _stepLabels.Length; i++)
        {
            var step = i + 1;
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            var isFuture = step > _currentStep;
            <button type="button"
                    class="btn btn-link text-decoration-none p-0 d-flex flex-column align-items-center flex-fill @(isFuture && !_submitted ? "text-muted" : "")"
                    style="@(isCurrent ? "font-weight:700;" : "") @(isFuture ? "opacity:0.5;" : "")"
                    disabled="@(isFuture || _submitted)"
                    @onclick="() => GoToStep(step)">
                <span class="rounded-circle d-inline-flex align-items-center justify-content-center mb-1"
                      style="width:36px;height:36px;
                             background:@(isCurrent ? "#0d6efd" : isCompleted ? "#198754" : "#dee2e6");
                             color:@(isCurrent || isCompleted ? "#fff" : "#6c757d");
                             font-size:0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <small style="font-size:0.75rem;">@_stepLabels[i]</small>
            </button>
        }
    </nav>

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="alert alert-success text-center py-5">
            <h3>&#10003; Application Submitted!</h3>
            <p class="mb-0">Your application ID is <strong>@_applicationId</strong>.</p>
            <p class="text-muted mt-2">We'll be in touch soon.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="alert alert-danger">@_error</div>
        }

        @switch (_currentStep)
        {
            case 1:
                @* ───── Step 1: Personal Info ───── *@
                <h4>Personal Information</h4>
                <div class="mb-3">
                    <label class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input class="form-control" @bind="_fullName" @bind:event="oninput" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="_email" @bind:event="oninput" />
                    @if (!string.IsNullOrEmpty(_emailError))
                    {
                        <div class="text-danger mt-1">@_emailError</div>
                    }
                </div>
                <div class="mb-3">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" @bind="_phone" @bind:event="oninput" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea class="form-control" rows="2" @bind="_address" @bind:event="oninput"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextStep" disabled="@_loading">
                        @if (_loading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Next
                    </button>
                </div>
                break;

            case 2:
                @* ───── Step 2: Work History ───── *@
                <h4>Work History</h4>
                @for (int i = 0; i < _workEntries.Count; i++)
                {
                    var idx = i;
                    var entry = _workEntries[idx];
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Position @(idx + 1)</h6>
                                @if (_workEntries.Count > 1)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                                }
                            </div>
                            <div class="row g-2 mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Company <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@entry.Company"
                                           @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@entry.Title"
                                           @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                            <div class="row g-2 mb-2">
                                <div class="col-md-4">
                                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                    <input type="date" class="form-control" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                                           @onchange="e => UpdateWork(idx, entry with { StartDate = DateTime.Parse((string?)e.Value ?? string.Empty) })" />
                                </div>
                                <div class="col-md-4">
                                    <label class="form-label">End Date</label>
                                    <input type="date" class="form-control"
                                           value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? string.Empty)"
                                           disabled="@entry.IsCurrent"
                                           @onchange="e => UpdateWork(idx, entry with { EndDate = string.IsNullOrEmpty((string?)e.Value) ? null : DateTime.Parse((string)e.Value) })" />
                                </div>
                                <div class="col-md-4 d-flex align-items-end mb-1">
                                    <div class="form-check">
                                        <input type="checkbox" class="form-check-input" id="@($"current-{idx}")"
                                               checked="@entry.IsCurrent"
                                               @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                                        <label class="form-check-label" for="@($"current-{idx}")">Current position</label>
                                    </div>
                                </div>
                            </div>
                            <div class="mb-0">
                                <label class="form-label">Description</label>
                                <textarea class="form-control" rows="2" value="@entry.Description"
                                          @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
                            </div>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 3:
                @* ───── Step 3: References ───── *@
                <h4>References</h4>
                @for (int i = 0; i < _references.Count; i++)
                {
                    var idx = i;
                    var r = _references[idx];
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between align-items-center mb-2">
                                <h6 class="mb-0">Reference @(idx + 1)</h6>
                                @if (_references.Count > 2)
                                {
                                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(idx)">Remove</button>
                                }
                            </div>
                            <div class="row g-2 mb-2">
                                <div class="col-md-6">
                                    <label class="form-label">Name <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@r.Name"
                                           @onchange="e => UpdateRef(idx, r with { Name = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                    <input class="form-control" value="@r.Relationship"
                                           @onchange="e => UpdateRef(idx, r with { Relationship = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                            <div class="row g-2">
                                <div class="col-md-6">
                                    <label class="form-label">Email <span class="text-danger">*</span></label>
                                    <input type="email" class="form-control" value="@r.Email"
                                           @onchange="e => UpdateRef(idx, r with { Email = (string?)e.Value ?? string.Empty })" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                                    <input type="tel" class="form-control" value="@r.Phone"
                                           @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
                                </div>
                            </div>
                        </div>
                    </div>
                }
                @if (_references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 4:
                @* ───── Step 4: Cover Letter ───── *@
                <h4>Cover Letter</h4>
                <div class="mb-2">
                    <textarea class="form-control" rows="10" maxlength="2000"
                              @bind="_coverLetter" @bind:event="oninput"></textarea>
                </div>
                <div class="text-muted mb-3 text-end">@(_coverLetter.Length) / 2000 characters</div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-primary" @onclick="NextStep">Next</button>
                </div>
                break;

            case 5:
                @* ───── Step 5: Review & Submit ───── *@
                <h4>Review Your Application</h4>

                @* Personal Info *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Personal Information</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(1)'>Edit</button>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>Name:</strong> @_fullName</p>
                        <p class="mb-1"><strong>Email:</strong> @_email</p>
                        <p class="mb-1"><strong>Phone:</strong> @_phone</p>
                        <p class="mb-0"><strong>Address:</strong> @_address</p>
                    </div>
                </div>

                @* Work History *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Work History</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(2)'>Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var w in _workEntries)
                        {
                            <div class="mb-2 @(w != _workEntries[^1] ? "pb-2 border-bottom" : "")">
                                <p class="mb-1"><strong>@w.Title</strong> at @w.Company</p>
                                <p class="mb-1 text-muted" style="font-size:0.9rem;">
                                    @w.StartDate.ToString("MMM yyyy") &ndash; @(w.IsCurrent ? "Present" : w.EndDate?.ToString("MMM yyyy") ?? "N/A")
                                </p>
                                @if (!string.IsNullOrWhiteSpace(w.Description))
                                {
                                    <p class="mb-0" style="font-size:0.9rem;">@w.Description</p>
                                }
                            </div>
                        }
                    </div>
                </div>

                @* References *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>References</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(3)'>Edit</button>
                    </div>
                    <div class="card-body">
                        @foreach (var r in _references)
                        {
                            <div class="mb-2 @(r != _references[^1] ? "pb-2 border-bottom" : "")">
                                <p class="mb-1"><strong>@r.Name</strong> — @r.Relationship</p>
                                <p class="mb-0 text-muted" style="font-size:0.9rem;">@r.Email · @r.Phone</p>
                            </div>
                        }
                    </div>
                </div>

                @* Cover Letter *@
                <div class="card mb-3">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>Cover Letter</strong>
                        <button class="btn btn-link btn-sm p-0" @onclick='() => GoToStep(4)'>Edit</button>
                    </div>
                    <div class="card-body">
                        <p style="white-space:pre-wrap;" class="mb-0">@_coverLetter</p>
                    </div>
                </div>

                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                    <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_loading">
                        @if (_loading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Submit Application
                    </button>
                </div>
                break;
        }
    }
</div>

@code {
    private static readonly string[] _stepLabels = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep = 1;
    private bool _submitted;
    private bool _loading;
    private string _error = string.Empty;
    private int _applicationId;

    // Step 1
    private string _fullName = string.Empty;
    private string _email = string.Empty;
    private string _phone = string.Empty;
    private string _address = string.Empty;
    private string _emailError = string.Empty;

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<RefModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = string.Empty;

    // ── Mutable working models ──

    private record WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record RefModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }

    // ── Navigation ──

    private void GoToStep(int step)
    {
        if (step < _currentStep && !_submitted)
        {
            _error = string.Empty;
            _currentStep = step;
        }
    }

    private void PrevStep()
    {
        _error = string.Empty;
        if (_currentStep > 1) _currentStep--;
    }

    private async Task NextStep()
    {
        _error = string.Empty;
        _emailError = string.Empty;

        if (!ValidateCurrentStep()) return;

        if (_currentStep == 1)
        {
            _loading = true;
            try
            {
                var valid = await ApplicationService.ValidateEmailAsync(_email);
                if (!valid)
                {
                    _emailError = "Please enter a valid email address.";
                    _loading = false;
                    return;
                }
            }
            finally { _loading = false; }
        }

        if (_currentStep < 5) _currentStep++;
    }

    // ── Validation ──

    private bool ValidateCurrentStep()
    {
        switch (_currentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
                    string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
                {
                    _error = "Please fill in all required fields.";
                    return false;
                }
                return true;

            case 2:
                foreach (var w in _workEntries)
                {
                    if (string.IsNullOrWhiteSpace(w.Company) || string.IsNullOrWhiteSpace(w.Title))
                    {
                        _error = "Each position must have a company name and job title.";
                        return false;
                    }
                }
                return true;

            case 3:
                foreach (var r in _references)
                {
                    if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                        string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
                    {
                        _error = "Please complete all reference fields.";
                        return false;
                    }
                }
                return true;

            default:
                return true;
        }
    }

    // ── Work History helpers ──

    private void UpdateWork(int index, WorkEntryModel updated) => _workEntries[index] = updated;
    private void AddWorkEntry() => _workEntries.Add(new());
    private void RemoveWorkEntry(int index) => _workEntries.RemoveAt(index);

    // ── Reference helpers ──

    private void UpdateRef(int index, RefModel updated) => _references[index] = updated;
    private void AddReference() { if (_references.Count < 3) _references.Add(new()); }
    private void RemoveReference(int index) => _references.RemoveAt(index);

    // ── Submit ──

    private async Task SubmitApplication()
    {
        _loading = true;
        _error = string.Empty;
        try
        {
            var personal = new PersonalInfo(_fullName.Trim(), _email.Trim(), _phone.Trim(), _address.Trim());
            var work = new WorkHistory(_workEntries.Select(w =>
                new WorkEntry(w.Company.Trim(), w.Title.Trim(), w.StartDate, w.IsCurrent ? null : w.EndDate, w.Description.Trim())).ToList());
            var refs = _references.Select(r =>
                new Reference(r.Name.Trim(), r.Relationship.Trim(), r.Email.Trim(), r.Phone.Trim())).ToList();
            var app = new JobApplication(personal, work, refs, _coverLetter.Trim());

            _applicationId = await ApplicationService.SubmitApplicationAsync(app);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally { _loading = false; }
    }
}
